def timestamp() -> str:
    return _dt.datetime.now().strftime("%Y-%m-%d %H:%M:%S")


def sha256_file(path: Path) -> str:
    h = hashlib.sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def ensure_clean_dir(path: Path, clean: bool) -> None:
    if clean and path.exists():
        shutil.rmtree(path)
    path.mkdir(parents=True, exist_ok=True)


def write_embedded_scripts(script_dir: Path) -> Dict[str, Path]:
    script_dir.mkdir(parents=True, exist_ok=True)
    out: Dict[str, Path] = {}
    manifest_rows = []
    for key, item in EMBEDDED_SCRIPTS.items():
        p = script_dir / item["filename"]
        p.write_text(item["content"], encoding="utf-8")
        observed = sha256_file(p)
        expected = item["sha256"]
        if observed != expected:
            raise RuntimeError(f"Embedded script checksum mismatch for {item['filename']}")
        out[key] = p
        manifest_rows.append([key, item["filename"], expected])
    with (script_dir / "00_EMBEDDED_SCRIPT_MANIFEST.csv").open("w", newline="", encoding="utf-8") as f:
        w = csv.writer(f)
        w.writerow(["key", "filename", "sha256"])
        w.writerows(manifest_rows)
    return out


def run_cmd(cmd: List[str], log_path: Path, dry_run: bool = False) -> None:
    line = " ".join(str(x) for x in cmd)
    with log_path.open("a", encoding="utf-8") as log:
        log.write(f"\n\n===== {timestamp()} =====\n")
        log.write(line + "\n")
        log.flush()
        print(f"[run] {line}", flush=True)
        if dry_run:
            log.write("[dry-run] skipped execution\n")
            return
        proc = subprocess.run(cmd, stdout=log, stderr=subprocess.STDOUT, text=True)
        if proc.returncode != 0:
            raise RuntimeError(f"Command failed with exit code {proc.returncode}: {line}\nSee log: {log_path}")


def count_csv_rows(path: Path) -> int:
    if not path.exists():
        return -1
    with path.open("r", encoding="utf-8", errors="replace") as f:
        return max(0, sum(1 for _ in f) - 1)


def copy_required_outputs(dirs: Dict[str, Path], collected_dir: Path) -> Tuple[List[Tuple[str, str, int]], List[Tuple[str, str]]]:
    collected_dir.mkdir(parents=True, exist_ok=True)
    copied: List[Tuple[str, str, int]] = []
    missing: List[Tuple[str, str]] = []
    for phase_key, filename in REQUIRED_CSVS:
        src = dirs[phase_key] / filename
        dst = collected_dir / filename
        if src.exists():
            shutil.copy2(src, dst)
            copied.append((phase_key, filename, count_csv_rows(dst)))
        else:
            missing.append((phase_key, filename))
    with (collected_dir / "00_COLLECTED_REQUIRED_CSVS_MANIFEST.csv").open("w", newline="", encoding="utf-8") as f:
        w = csv.writer(f)
        w.writerow(["phase", "filename", "rows", "status"])
        for phase_key, filename, rows in copied:
            w.writerow([phase_key, filename, rows, "copied"])
        for phase_key, filename in missing:
            w.writerow([phase_key, filename, "", "missing"])
    return copied, missing


def copy_phase_reports(dirs: Dict[str, Path], report_dir: Path) -> None:
    report_dir.mkdir(parents=True, exist_ok=True)
    for phase_key, filename in PHASE_REPORTS:
        src = dirs.get(phase_key, Path("__missing__")) / filename
        if src.exists():
            shutil.copy2(src, report_dir / f"{phase_key}__{filename}")


def write_first_look(outdir: Path, dirs: Dict[str, Path], copied, missing, args) -> None:
    first = outdir / "00_FIRST_LOOK_README.md"
    lines = []
    lines.append("# First-look summary")
    lines.append("")
    lines.append(f"Created: {timestamp()}")
    lines.append(f"Source root: {Path(args.source_root).resolve()}")
    lines.append(f"Output root: {outdir.resolve()}")
    lines.append("")
    lines.append("## Main outputs")
    lines.append("")
    lines.append("- `10_MANUSCRIPT_REQUIRED_CSVS/`: CSV files used for Results tables and Figures 1-6")
    lines.append("- `11_RESULTS_FIGURES/`: manuscript figures, if figure generation was enabled")
    lines.append("- `00_PHASE_REPORTS/`: copied phase reports")
    lines.append("- `00_RUN_ALL_REANALYSIS.log`: full execution log")
    lines.append("- `_embedded_phase_scripts/00_EMBEDDED_SCRIPT_MANIFEST.csv`: checksum manifest of embedded scripts")
    lines.append("")
    lines.append("## Phase directories")
    lines.append("")
    for key, p in dirs.items():
        if key != "scripts":
            lines.append(f"- {key}: `{p}`")
    lines.append("")
    lines.append("## Required CSV collection")
    lines.append("")
    lines.append(f"Copied: {len(copied)}")
    lines.append(f"Missing: {len(missing)}")
    if missing:
        lines.append("")
        lines.append("Missing files:")
        for phase_key, filename in missing:
            lines.append(f"- {phase_key} / {filename}")
    lines.append("")
    lines.append("## Reproduction note")
    lines.append("")
    lines.append("This file reanalyzes existing raw simulation logs. It does not generate the raw simulation logs themselves.")
    first.write_text("\n".join(lines) + "\n", encoding="utf-8")


def parse_args() -> argparse.Namespace:
    ap = argparse.ArgumentParser(description="All-in-one Phase 1-7 reanalysis pipeline for the embodied population signal study.")
    ap.add_argument("--source-root", required=True, help="Raw source root containing shards/<scenario>/ logs.")
    ap.add_argument("--outdir", default=str(Path.home() / "Desktop" / "V11_SIGNAL_SYSTEM_REANALYSIS_ALL_IN_ONE"), help="Output directory.")
    ap.add_argument("--clean", action="store_true", help="Remove the output directory before running.")
    ap.add_argument("--chunksize", type=int, default=250000, help="Chunk size for phase scripts that stream CSV files.")
    ap.add_argument("--phase1-chunksize", type=int, default=200000, help="Chunk size for the Phase 1 signal-ecology script.")
    ap.add_argument("--bootstrap", type=int, default=500, help="Bootstrap samples for Phase 1b. Use 0 to disable.")
    ap.add_argument("--n-permutations", type=int, default=32, help="Permutation count for Phase 7 null controls.")
    ap.add_argument("--skip-figures", action="store_true", help="Run Phase 1-7 only; do not generate Figures 1-6.")
    ap.add_argument("--dry-run", action="store_true", help="Print and log commands without executing phase scripts.")
    return ap.parse_args()


def main() -> None:
    args = parse_args()
    source_root = Path(args.source_root).expanduser().resolve()
    outdir = Path(args.outdir).expanduser().resolve()

    if not source_root.exists():
        raise FileNotFoundError(f"source-root does not exist: {source_root}")
    if not (source_root / "shards").exists():
        raise FileNotFoundError(f"source-root must contain a shards/ directory: {source_root}")

    ensure_clean_dir(outdir, args.clean)
    log_path = outdir / "00_RUN_ALL_REANALYSIS.log"
    log_path.write_text(f"All-in-one reanalysis started: {timestamp()}\n", encoding="utf-8")

    script_dir = outdir / "_embedded_phase_scripts"
    scripts = write_embedded_scripts(script_dir)

    dirs: Dict[str, Path] = {
        "scripts": script_dir,
        "phase1": outdir / "01_PHASE1_SIGNAL_ECOLOGY",
        "phase1b": outdir / "02_PHASE1B_CHANNEL_DIRECTION",
        "phase2": outdir / "03_PHASE2_SENDER_GROUNDING",
        "phase2b": outdir / "04_PHASE2B_STANDARDIZED_SENDER_GROUNDING",
        "phase3": outdir / "05_PHASE3_RECEIVER_ACTION",
        "phase4": outdir / "06_PHASE4_TEMPORAL_DEVELOPMENT",
        "phase5": outdir / "07_PHASE5_POPULATION_SHARING",
        "phase6": outdir / "08_PHASE6_SEQUENCE_DEPENDENCE",
        "phase7": outdir / "09_PHASE7_NULL_MATCHED_CONTROLS",
        "collected": outdir / "10_MANUSCRIPT_REQUIRED_CSVS",
        "figures": outdir / "11_RESULTS_FIGURES",
        "reports": outdir / "00_PHASE_REPORTS",
    }

    py = sys.executable
    clean_flag = ["--clean"]

    run_cmd([py, str(scripts["phase1_signal_ecology"]), "--source-root", str(source_root), "--outdir", str(dirs["phase1"]), "--chunksize", str(args.phase1_chunksize), *clean_flag], log_path, args.dry_run)
    run_cmd([py, str(scripts["phase1b_channel_direction"]), "--phase1-dir", str(dirs["phase1"]), "--outdir", str(dirs["phase1b"]), "--bootstrap", str(args.bootstrap), *clean_flag], log_path, args.dry_run)
    run_cmd([py, str(scripts["phase2_sender_grounding"]), "--source-root", str(source_root), "--outdir", str(dirs["phase2"]), "--chunksize", str(args.chunksize), *clean_flag], log_path, args.dry_run)
    run_cmd([py, str(scripts["phase2b_standardized_sender_grounding"]), "--phase2-dir", str(dirs["phase2"]), "--outdir", str(dirs["phase2b"]), *clean_flag], log_path, args.dry_run)
    run_cmd([py, str(scripts["phase3_receiver_action"]), "--source-root", str(source_root), "--outdir", str(dirs["phase3"]), "--chunksize", str(args.chunksize), *clean_flag], log_path, args.dry_run)
    run_cmd([py, str(scripts["phase4_temporal_development"]), "--phase1-dir", str(dirs["phase1b"]), "--phase2b-dir", str(dirs["phase2b"]), "--phase3-dir", str(dirs["phase3"]), "--outdir", str(dirs["phase4"]), *clean_flag], log_path, args.dry_run)
    run_cmd([py, str(scripts["phase5_population_sharing"]), "--source-root", str(source_root), "--outdir", str(dirs["phase5"]), "--chunksize", str(args.chunksize), *clean_flag], log_path, args.dry_run)
    run_cmd([py, str(scripts["phase6_sequence_dependence"]), "--source-root", str(source_root), "--outdir", str(dirs["phase6"]), "--chunk-size", str(args.chunksize), *clean_flag], log_path, args.dry_run)
    run_cmd([py, str(scripts["phase7_null_matched_controls"]), "--source-root", str(source_root), "--phase2b-dir", str(dirs["phase2b"]), "--outdir", str(dirs["phase7"]), "--n-permutations", str(args.n_permutations), "--chunk-size", str(args.chunksize), *clean_flag], log_path, args.dry_run)

    if args.dry_run:
        copied, missing = [], []
    else:
        copied, missing = copy_required_outputs(dirs, dirs["collected"])
        copy_phase_reports(dirs, dirs["reports"])
        if not args.skip_figures:
            run_cmd([py, str(scripts["figures"]), "--input-dir", str(dirs["collected"]), "--outdir", str(dirs["figures"]), *clean_flag], log_path, args.dry_run)

    write_first_look(outdir, dirs, copied, missing, args)
    with log_path.open("a", encoding="utf-8") as log:
        log.write(f"\n===== {timestamp()} =====\n")
        log.write("All-in-one reanalysis completed.\n")
        log.write(f"Output root: {outdir}\n")
        log.write(f"Copied required CSVs: {len(copied)}\n")
        log.write(f"Missing required CSVs: {len(missing)}\n")
    print("[done] All-in-one reanalysis completed.", flush=True)
    print(f"[first-look] {outdir / '00_FIRST_LOOK_README.md'}", flush=True)


if __name__ == "__main__":
    main()
